#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
int m,n,q;
int dfs(int x,int y,int now)
{
	if(x==y) return now;
	if(y/x>1)
	{
		return now;
	}
	return dfs(y-x,x,!now);
}
int main()
{
	cin>>q;
	while(q--)
	{
		cin>>n>>m;
		if(n>m) swap(n,m);
		if(dfs(n,m,0)) cout<<"Ollie wins\n";
		else cout<<"Stan wins\n";
	}
	return 0;
}
